+    config: &mut mcp_agent_mail_core::Config,
+    last_restart_sleep_ms: &mut u64,
+    mut should_abort: AbortFn,
+    mut on_retry_error: RetryFn,
+    mut spawn_fn: SpawnFn,
+    mut sleep_fn: SleepFn,
