+                *last_restart_sleep_ms = restart_backoff_ms(*last_restart_sleep_ms);
+                on_retry_error(&err, *last_restart_sleep_ms);
+                sleep_fn(Duration::from_millis(*last_restart_sleep_ms));
+            }
+        }
+    }
